namespace sv_9e946314d26a4c738730c78c5cb7b968.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Italian pizza with fresh mozzarella and basil.", 25),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg, and pecorino.", 20),
            new(3, "Tiramisu", "Layered coffee-flavoured dessert with mascarpone.", 30),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Grilled chicken in a rich spiced tomato sauce.", 45),
            new(5, "Palak Paneer", "Creamy spinach curry with paneer cubes.", 35),
            new(6, "Biryani", "Fragrant layered rice dish with spices and meat.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos Al Pastor", "Spit-grilled pork tacos with pineapple and cilantro.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime, onion, and chili.", 10),
            new(9, "Enchiladas Verdes", "Corn tortillas rolled with chicken and green salsa.", 35),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_9e946314d26a4c738730c78c5cb7b968.Services
@inject IRecipeService RecipeService
@inject NavigationManager Navigation
@inject ILogger<Recipes> Logger
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes for Cuisine @CuisineId</h1>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _errorMessage;

    private CancellationTokenSource? _loadCts;
    private int _lastLoadedCuisineId;

    private IEnumerable<Recipe> DisplayedRecipes =>
        Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes!.OrderByDescending(r => r.Id),
            "popular" => _recipes!.OrderBy(r => r.PrepTimeMinutes),
            _ => _recipes!
        };

    protected override Task OnParametersSetAsync()
    {
        if (CuisineId != _lastLoadedCuisineId)
        {
            return LoadRecipesAsync();
        }

        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load
        _loadCts?.Cancel();
        _loadCts?.Dispose();
        _loadCts = new CancellationTokenSource();
        var ct = _loadCts.Token;

        _lastLoadedCuisineId = CuisineId;
        _errorMessage = null;

        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, ct);
            _recipes = results;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // A newer load superseded this one — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _errorMessage = "Something went wrong loading recipes. Please try again.";
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    public void Dispose()
    {
        _loadCts?.Cancel();
        _loadCts?.Dispose();
    }
}

